```java
public class Test {
    public static void main(String[] args) {
        try {
            readFile();
            System.out.print("A");
        } catch (IOException e) {
            System.out.print("B");
        } finally {
            System.out.print("C");
        }
    }
    public static void readFile() throws IOException {
        FileReader file = new FileReader("test.txt");
    }
}
